#include <stdio.h>

void insertLast(int arr[], int *n, int val) {

    // Insert val at last
    arr[*n] = val;

    // Increase the current size
    (*n)++;
}

int main() {
    int arr[7] = {10, 20, 30, 40, 50};
    int n = 5;
    int val = 25;

    // Insert the value at the end
    insertLast(arr, &n, val);

    for (int i = 0; i < n; i++)
        printf("%d ", arr[i]);
    return 0;
}
